package internal

import (
  "database/sql"
  "net/http"
)

func UserByID(db *sql.DB, r *http.Request) (*sql.Rows, error) {
  id := r.URL.Query().Get("id")
  return db.Query("SELECT * FROM users WHERE id = $1", id)
}

package internal

import "testing"
func TestUserByIDExists(t *testing.T) { _ = UserByID }
